data.content:
**MSTest does not have `Assert.IsGreaterThan` or `Assert.IsInRange`** — those don't exist. Here's what to use instead:

### MSTest options for boundary/comparison checks:

| Need | Use |
|------|-----|
| Floating-point equality | `Assert.AreEqual(expected, actual, delta)` |
| Comparisons | `Assert.IsTrue(value >= 90)` |
| Exceptions | `Assert.ThrowsException<T>(action)` |

### Example tests for your `ScoreCalculator`:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Scoring;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    [TestMethod]
    public void CalculatePercentage_ReturnsCorrectValue()
    {
        double result = _calc.CalculatePercentage(7, 10);
        Assert.AreEqual(70.0, result, 0.001); // delta for floating-point tolerance
    }

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        double result = _calc.CalculatePercentage(10, 10);
        Assert.AreEqual(100.0, result, 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_ReturnsZero()
    {
        double result = _calc.CalculatePercentage(0, 10);
        Assert.AreEqual(0.0, result, 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_InvalidArgs_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(5, 0));
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(80.0, "B")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_AtBoundaries_ReturnsExpected(double pct, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(pct));
    }

    [TestMethod]
    public void NormalizeScore_ClampedTo100()
    {
        double result = _calc.NormalizeScore(150, 100);
        Assert.AreEqual(100.0, result, 0.001);
    }

    [TestMethod]
    public void NormalizeScore_ResultInValidRange()
    {
        double result = _calc.NormalizeScore(50, 200);
        // No IsInRange — use IsTrue for range checks
        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Expected 0–100 but got {result}");
        Assert.AreEqual(25.0, result, 0.001);
    }
}
```

### Key takeaways:
- **`Assert.AreEqual(expected, actual, delta)`** — your best tool for numeric boundary tests (the 3rd arg is tolerance)
- **`Assert.IsTrue(condition, message)`** — fallback for range/comparison checks; always add a message for useful failure output
- **`Assert.ThrowsException<T>`** — verifies guard clauses throw on invalid input
